#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_NODES 10000
#define MAX_CHILDREN 2

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform BFS traversal and find the top view
void topView(Node* root) {
    if (!root) return;

    // Create a queue for BFS traversal
    Node** queue = (Node**) malloc(sizeof(Node*) * MAX_NODES);
    int* hd = (int*) malloc(sizeof(int) * MAX_NODES);
    int front = 0, rear = 0;

    // Enqueue the root node
    queue[rear] = root;
    hd[rear] = 0;
    rear++;

    // Create a map to store the top view nodes
    int map[MAX_NODES] = {0};

    while (front < rear) {
        Node* node = queue[front];
        int horizontalDistance = hd[front];
        front++;

        // If we haven't encountered a node at the current horizontal distance before
        if (map[horizontalDistance + MAX_NODES / 2] == 0) {
            map[horizontalDistance + MAX_NODES / 2] = node->val;
        }

        // Enqueue the children of the current node
        if (node->left) {
            queue[rear] = node->left;
            hd[rear] = horizontalDistance - 1;
            rear++;
        }
        if (node->right) {
            queue[rear] = node->right;
            hd[rear] = horizontalDistance + 1;
            rear++;
        }
    }

    // Print the top view nodes
    for (int i = 0; i < MAX_NODES; i++) {
        if (map[i] != 0) {
            printf("%d ", map[i]);
        }
    }
    printf("\n");
}

int main() {
    int N;
    scanf("%d", &N);

    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);

        // Create a new node for the child
        Node* child = createNode(ci);

        // Find the parent node
        Node* parent = root;
        if (parent == NULL) {
            parent = createNode(pi);
            root = parent;
        } else {
            Node* temp = parent;
            while (temp->left != NULL && temp->right != NULL) {
                if (temp->left->val == pi) {
                    temp = temp->left;
                } else if (temp->right->val == pi) {
                    temp = temp->right;
                } else {
                    // If the parent node is not found, create a new node for the parent
                    Node* newParent = createNode(pi);
                    if (temp->left == NULL) {
                        temp->left = newParent;
