import java.util.Map;
import java.util.HashMap;
import java.util.Scanner;
public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        Node left;
        Node right;
        Node(int node_value) {
            val = node_value;
            left = right = null;
        }
    }

    // Function to perform BFS traversal and find the top view
    public static void topView(Node root) {
        if (root == null) return;

        // Create a queue for BFS traversal
        Queue<Node> queue = new LinkedList<>();
        queue.add(root);
        Queue<Integer> hd = new LinkedList<>();
        hd.add(0);

        // Create a map to store the top view nodes
        Map<Integer, Integer> v = new HashMap<>();

        while (!queue.isEmpty()) {
            Node node = queue.poll();
            int horizontalDistance = hd.poll();

            // If we haven't encountered a node at the current horizontal distance before
            if (!v.containsKey(horizontalDistance)) {
                v.put(horizontalDistance, node.val);
            }

            // Enqueue the children of the current node
            if (node.left != null) {
                queue.add(node.left);
                hd.add(horizontalDistance - 1);
            }
            if (node.right != null) {
                queue.add(node.right);
                hd.add(horizontalDistance + 1);
            }
        }

        // Print the top view nodes
        for (int value : v.values()) {
            System.out.print(value + " ");
        }
        System.out.println();
    }

